<?php $e=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES|ENT_SUBSTITUTE,"UTF-8");$now=gmdate("Y-m-d H:i:s"); ?>
<div id="page-content" class="page-wrapper clearfix"><div class="page-title clearfix"><h4><?php echo $e($booking->booking_number." — ".$booking->title); ?></h4><div class="title-button-group"><?php if($can_manage&&in_array($booking->status,["hold","pending_confirmation","confirmed"],true)&&$booking->starts_at_utc>$now){echo modal_anchor(get_uri("grupo_donato/bookings/modal"),"<i data-feather='edit' class='icon-16'></i> ".app_lang("edit"),["class"=>"btn btn-default","data-post-id"=>$booking->id,"title"=>app_lang("edit")]);}echo anchor(get_uri("grupo_donato/bookings"),app_lang("back"),["class"=>"btn btn-default"]); ?></div></div>
<div class="row"><div class="col-md-7"><div class="card"><div class="card-header"><h4><?php echo app_lang("gd_booking_details"); ?></h4></div><div class="card-body"><div class="row"><div class="col-md-4"><strong><?php echo app_lang("gd_status"); ?></strong><br><?php echo app_lang("gd_booking_status_".$booking->status); ?></div><div class="col-md-4"><strong><?php echo app_lang("gd_type"); ?></strong><br><?php echo app_lang("gd_booking_type_".$booking->booking_type); ?></div><div class="col-md-4"><strong><?php echo app_lang("gd_lock_version"); ?></strong><br><?php echo (int)$booking->lock_version; ?></div></div><hr><div class="row"><div class="col-md-6"><strong><?php echo app_lang("gd_customer"); ?></strong><br><?php echo $e($booking->customer_name??"-"); ?></div><div class="col-md-6"><strong><?php echo app_lang("gd_contact"); ?></strong><br><?php echo $e($booking->contact_name??"-"); ?></div></div><hr><strong><?php echo app_lang("gd_usage_schedule"); ?></strong><br><?php echo $e((new DateTimeImmutable($booking->starts_at_utc,new DateTimeZone('UTC')))->setTimezone(new DateTimeZone($timezone))->format('d/m/Y H:i')." — ".(new DateTimeImmutable($booking->ends_at_utc,new DateTimeZone('UTC')))->setTimezone(new DateTimeZone($timezone))->format('d/m/Y H:i')); ?> <small class="text-muted"><?php echo $e($timezone); ?></small>
<hr><table class="table table-sm"><thead><tr><th><?php echo app_lang("gd_resource"); ?></th><th><?php echo app_lang("gd_buffers"); ?></th><th><?php echo app_lang("gd_effective_occupancy"); ?></th></tr></thead><tbody><?php foreach($booking->resources as $r){ ?><tr><td><?php echo $e($r->resource_code." — ".$r->resource_name); ?></td><td><?php echo (int)$r->buffer_before_minutes." / ".(int)$r->buffer_after_minutes." min"; ?></td><td><?php echo $e((new DateTimeImmutable($r->occupancy_starts_at_utc,new DateTimeZone('UTC')))->setTimezone(new DateTimeZone($timezone))->format('d/m/Y H:i')." — ".(new DateTimeImmutable($r->occupancy_ends_at_utc,new DateTimeZone('UTC')))->setTimezone(new DateTimeZone($timezone))->format('d/m/Y H:i')); ?></td></tr><?php } ?></tbody></table><?php if($booking->hold_expires_at_utc){ ?><hr><strong><?php echo app_lang("gd_hold_until"); ?></strong><br><?php echo $e($booking->hold_expires_at_utc); ?> UTC<?php } ?><?php if($booking->notes){ ?><hr><strong><?php echo app_lang("gd_notes"); ?></strong><br><?php echo nl2br($e($booking->notes)); ?><?php } ?><?php if($booking->metadata){ ?><hr><strong><?php echo app_lang("gd_metadata_json"); ?></strong><pre><?php echo $e(json_encode(json_decode($booking->metadata,true),JSON_PRETTY_PRINT|JSON_UNESCAPED_UNICODE)); ?></pre><?php } ?></div></div></div>
<div class="col-md-5"><?php if($can_status){ ?><div class="card"><div class="card-header"><h4><?php echo app_lang("gd_actions"); ?></h4></div><div class="card-body" id="gd-lifecycle-actions"><?php if(in_array($booking->status,["hold","pending_confirmation"],true)){ ?><button data-action="confirm" class="btn btn-success mr5"><?php echo app_lang("gd_confirm_booking"); ?></button><?php }if($booking->status==="confirmed"){ ?><button data-action="start" class="btn btn-primary mr5"><?php echo app_lang("gd_start_booking"); ?></button><button data-action="no-show" data-reason="1" class="btn btn-warning mr5"><?php echo app_lang("gd_no_show"); ?></button><?php }if($booking->status==="in_progress"){ ?><button data-action="complete" class="btn btn-success mr5"><?php echo app_lang("gd_complete_booking"); ?></button><?php }if(in_array($booking->status,["hold","pending_confirmation","confirmed","in_progress"],true)){ ?><button data-action="cancel" data-reason="1" class="btn btn-danger"><?php echo app_lang("gd_cancel_booking"); ?></button><?php } ?></div></div><?php } ?><div class="card"><div class="card-header"><h4><?php echo app_lang("gd_booking_history"); ?></h4></div><div class="card-body"><?php foreach($booking->events as $ev){ ?><div class="mb10"><strong><?php echo app_lang("gd_booking_event_".$ev->event_type); ?></strong> <small class="text-muted"><?php echo $e($ev->created_at." UTC"); ?></small><?php if($ev->from_status||$ev->to_status){ ?><br><small><?php echo $e(($ev->from_status??"-")." → ".($ev->to_status??"-")); ?></small><?php }if($ev->reason){ ?><br><?php echo $e($ev->reason); ?><?php } ?></div><?php } ?></div></div></div></div></div>
<script>$(document).ready(function(){$('#gd-lifecycle-actions button').on('click',function(){var b=$(this),reason='';if(b.data('reason')){reason=window.prompt('<?php echo addslashes(app_lang("gd_reason")); ?>','');if(!reason){return;}}$.post('<?php echo_uri("grupo_donato/bookings/".(int)$booking->id."/"); ?>'+b.data('action'),{reason:reason}).done(function(r){if(r.success){location.reload();}else{appAlert.error(r.message);}});});});</script>
